<template>
  <div id="social-media" class="hidden-xs">
      <div class="social-icons">
    <ul class="accordion">
      <li class="tabs">
        <div class="social-links twitter-icon">
          <a href="https://twitter.com/CristoElgin">Twitter</a>
        </div>
        <div class="content">
          <h1>{{twitterFollowers}} followers</h1>
        </div>
      </li>
      <li class="tabs">
        <div class="social-links facebook-icon">
          <a href="https://www.facebook.com/Iglesia-de-Cristo-en-Elgin-243271119073381/">Facebook</a>
        </div>
        <div class="content">
          <h1>{{facebookLikes}} likes</h1>
        </div>

      </li>
    
      <li class="tabs">
        <div class="social-links insta-icon">
          <a href="https://www.instagram.com/cristoelgin/">Instagram</a>
        </div>
        <div class="content">
          <h1>{{instagramFollowers}} followers</h1>
        </div>
        
      </li>
      <li class="tabs">
        <div class="social-links youtube-icon">
          <a href="https://www.youtube.com/user/TheCatch13777/featured">Youtube</a>  
        </div>
        <div class="content">
          <h1>{{youtubeViews}} views</h1>
        </div>
      </li>
    </ul>
      </div>
  </div>
</template>

<script>

import axios from 'axios';

export default {
  name: 'social-media',
  data(){
      return {
          youtubeViews: "",
          facebookLikes: "",
          twitterFollowers: "",
          instagramFollowers: "",     
      }
  },
  methods: {
        onReady: function(instance, CountUp) {
        const that = this;
        instance.update(that.endVal + 100);
      },
    getYoutube: function(){
        
      axios.get("https://cors-anywhere.herokuapp.com/https://www.youtube.com/user/TheCatch13777/about").then(response => {
                    var text = response.data;


                    var result = text.substring(text.lastIndexOf("viewCountText")+33, text.lastIndexOf("bold")-3);

                    this.youtubeViews = result.replace(",", '');

                 

      }) ;
    },
    getFacebook: function(){
        axios.get("https://cors-anywhere.herokuapp.com/https://www.facebook.com/plugins/page.php?href=https%3A%2F%2Fwww.facebook.com%2FIglesia-de-Cristo-en-Elgin-243271119073381%2F&tabs&width=340&height=130&small_header=false&adapt_container_width=false&hide_cover=false&show_facepile=false&appId=555207491508441").then(response => {
                    var text = response.data;

                    var result = text.substring(text.lastIndexOf("_1drq")+33, text.lastIndexOf("likes"));
                    
                    this.facebookLikes = result;

      }) ;
    },
    getTwitter: function(){
         axios.get("https://cors-anywhere.herokuapp.com/https://twitter.com/CristoElgin?ref_src=twsrc%5Etfw").then(response => {
                    var text = response.data;

                    var result = text.substring(text.lastIndexOf("followers_count&quot;:")+22, text.lastIndexOf(",&quot;friends_count&quot;:"));
              
                    this.twitterFollowers = result;

      }) ;
    },
    getInsta: function(){
        axios.get("https://www.instagram.com/cristoelgin/").then(response => {
                            var text = response.data;

                            var result = text.substring(text.lastIndexOf("meta content=")+14, text.lastIndexOf("og:type")-10);

                            var lastresult = result.substring(result.lastIndexOf("meta content="), result.lastIndexOf("Followers"));
                        
                    
                            this.instagramFollowers = lastresult;
                
            }) ;

          
    }

  },
  mounted(){
      this.getYoutube();
      this.getFacebook();
      this.getTwitter();
      this.getInsta();
      
  }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
@import '../../assets/main.scss';

@import '../../assets/bootstrap.min';

$border: #5ab2ca;
$geneicons: #fff;
$backgroundColor: #f77462;
$list: #6dc5dd;
@font-face {
  font-family: 'Genericons';
  src: url('https://s3-us-west-2.amazonaws.com/s.cdpn.io/53819/genericons-regular-webfont.eot');
  src: url('https://s3-us-west-2.amazonaws.com/s.cdpn.io/53819/genericons-regular-webfont.woff') format('woff'),
     url('https://s3-us-west-2.amazonaws.com/s.cdpn.io/53819/genericons-regular-webfont.eot') format('truetype');
  font-weight: normal;
  font-style: normal;
}

[class*="genericon"] {
  display: inline-block;
  width: 16px;
  height: 16px;
  -webkit-font-smoothing: antialiased;
  font-size: 16px;
  line-height: 1;
  font-family: 'Genericons';
  text-decoration: inherit;
  font-weight: normal;
  font-style: normal;
  vertical-align: top;
}

/* IE7 */
[class*="genericon"] {
  *overflow: auto;
  *zoom: 1;
  *display: inline;
}


.accordion {
  background: $border;
  width: 100%;
  // min-width: 950px;
  display: block;
  list-style-type: none;
  overflow: hidden;
  height: 70vh;
  font-size: 0;
  padding: 0;

}

.content {
    position: absolute;
    margin-left: 100%;
    left: 50%;
    top:70%;
    color:white;
    margin-right: -50%;
    transform: translate(-50%, -50%);
    transition: all 0.4s 0.1s ease-in-out ;
}

.tabs:hover .content {
    margin-left: 0%;
}

.tabs {
  display: inline-block;
  background-color: #222;
  border-right: black 3px solid;
  width: 25%;
  height: 100%;
  overflow: hidden;
  position: relative;
  margin: 0;
  font-size: 16px;
  transition: all 0.4s 0.1s ease-in-out ;

  &:hover {
    width: 25%;

    .social-links {
      a {
        &:before {
          margin-left: 500px;
        }

        &:after {
          margin-left: -5px;
        }
      }
    }
  }
}

.tabs:hover .paragraph {
  margin-left: 10%;
  transition: all 1s;
}

.social-links {
  display: block;

  a {
    display: block;
    text-indent: -9999px;
    font-size: 0;
    line-height: 0;


    &:before, &:after {
  transition: all 0.4s 0.1s ease-in-out ;
      width: 110px;
      height: 100%;
      position: absolute;
      text-indent: 0;
      padding-top: 55%;
      padding-left: 40%;
      display: block;
      font: normal 5.5vw Genericons;
      color: $geneicons;
    }

    &:after {
      font-size: 48px;
      width: 100%;
      padding-left: 40%;
      padding-right: 50%;
      padding-top: 50%;
      margin-left: 100%;
    font: normal 5.5vw Genericons;

    }
  }
}

.twitter-icon {
  a {
    &:before, &:after {
      content: '\f202 ';
    }

    &:after {
      background-image:linear-gradient(#7adcf9, #4bc9f5);
    }
  }
}

.facebook-icon {
  a {
    &:before, &:after {
      content: '\f204';
    }

    &:after {
      background-image:linear-gradient(#548abf, #295b9e);
    }
  }
}


.insta-icon {
  a {
    &:before, &:after {
      content: '\f215';
    }

    &:after {
background: linear-gradient( #400080, transparent), linear-gradient(200deg, #d047d1, #ff0000,#ffff00);    }
  }
}

.youtube-icon {
  a {
    &:before, &:after {
      content: '\f213';
    }

    &:after {
      background-image:linear-gradient(#df192a, #c41222);
    }
  }
}



@media screen and (max-width: 748px) {

    #social-media {
        height: 90vh;
     
    }

    
.accordion {
  background: #222;
  width: 100%;
  min-width: 350px;
  margin-top: 50px;
  display: block;
  list-style-type: none;
  overflow: hidden;
  height: 100vh;
  font-size: 0;
  padding: 0;

}

.content {
    position: absolute;
    margin-left: 0%;
    left: 80%;
    top:30%;
    margin-right: -50%;
    transform: translate(-50%, -50%);
    transition: all 0.4s 0.1s ease-in-out ;

    h1 {
        font-size: 20px;
        color:white;
        font-weight: 300;
    }
}

.tabs:hover .content {
    margin-left: 0%;
}

.tabs {
  display: block;
  background-color: #222;
  border-right: black 3px solid;
  width: 100vw;
  height: 20%;
  overflow: hidden;
  position: relative;
  margin: 0;
  font-size: 16px;
  transition: all 0.4s 0.1s ease-in-out ;

}

.tabs:hover .paragraph {
  margin-left: 10%;
  transition: all 1s;
}

.social-links {
  display: block;

  a {
    display: block;
    text-indent: -9999px;
    font-size: 0;
    line-height: 0;


    &:before, &:after {
  transition: all 0.4s 0.1s ease-in-out ;
      width: 110px;
      height: 100%;
      position: absolute;
      text-indent: 0;
      padding-top:0%;
      margin-top: 10px;
      padding-left: 10%;
      display: block;
      font: normal 20vw Genericons;
      color: $geneicons;
    }

    &:after {
      font-size: 48px;
      width: 100%;
      padding-left: 40%;
      padding-right: 50%;
      padding-top: 50%;
      margin-left: 100%;
    font: normal 5.5vw Genericons;

    }
  }
}

     
}

   



  

    

</style>



