// Need to make data dymanic so ricardo can change series and picture

<template>
     <div id="topic">
         <div class="parallax hidden-xs"></div>
         <div class="parallax-mobile visible-xs"></div>
        <!-- <img class="img-title center" src="../../assets/img/texts/dias.png" alt=""><br> -->
            
            <div class="wrapper">
                <div class="boxes">
                     <h1>DIAS<br> DE<br> REUNION</h1>
                </div>
                <div class="boxes">
                    <div class="box" v-for="day in days" @click="clickedDay(day); showingModal = true;">
                        <div class="day center">
                            <h2>{{day.text}}</h2>
                            <!-- <img :src="day.img"><br> -->
                                <!-- <div class="divider"></div><br> -->
                            <h4>{{day.time}}</h4>
                        </div>
                    </div>
                </div>

        <transition name="slide-right">
               <div class="modal2" id="addModal" v-if="showingModal" >
                <div class="modalContainer">
                    <div class="modalHeading">
                        <div class="close" @click="showingModal = false;">
                            &times;
                        </div>
                        
                        <div class="modalContent">
                            <div class="mcback" :style="{ 'background-image': 'url(' + dayClicked.dayImg + ')'}"></div>
                            <div class="mctext">
                                 <h2>{{dayClicked.text}}</h2>
                                <h3>{{dayClicked.day}}</h3>
                                <p>{{dayClicked.details}}</p>
                            </div>
                               
                        </div>
                    </div>
                </div>
            </div>
            </transition>
             
            </div>

     
        
     </div>
</template>

<script>
export default {
  name: 'topics',
  data(){
      return {
          days: [
              { img: require('../../assets/img/texts/lunes.png'), time: '7-8 PM', dayImg: 'https://source.unsplash.com/VRr9a2rOoBI', text: "Lunes", details: ""},
              { img: require('../../assets/img/texts/mier.png'), time: '7-8 PM', dayImg: 'https://source.unsplash.com/lLk1oJA7Wkg', text: "Miercoles", day: "Current Series", details: " Brief description of series"},
              { img: require( '../../assets/img/texts/dom-am.png'), time: '9:30-11 AM', dayImg: 'https://source.unsplash.com/YS3Q5vroxtg', text: "Domingo AM", day: "Current Series", details: " Brief description of series"},
              { img: require( '../../assets/img/texts/dom-pm.png'), time: '3-4 PM' ,dayImg: 'https://source.unsplash.com/t1QUoAMyXDs', text: "Domingo PM", day: "Current Series", details: " Brief description of series"},
            ],
            dayClicked: {},
            showingModal: false
      }
  },
  methods: {
      clickedDay(day){
          this.dayClicked = day;
          console.log("day clicked")
          console.log(day);
      }
  }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
@import '../../assets/main.scss';


@import '../../assets/bootstrap.min';


#topic {
    background: #222;
    height: 100vh;
    position: relative;

}
.wrapper {
    height: 100vh;
    position: relative;

}

h1 {
  position: relative;
  color: #fff;
  opacity: 1;
  font-size: 7.5vw;
  text-align: left;
  font-weight: 400;
  z-index: 0;
  left: 50px;
  top: 10vh;
}
.parallax {
    background-image: url('../../assets/img/intro/visitback.jpg');
    background-repeat: no-repeat;
    position: absolute;
    z-index: 0;
    left: 0;
    opacity: .2;
    background-attachment: fixed;
    background-position: 80px 0px;
    background-size: 100% auto;
    height: 100%;
    width: 100%;
}


    .day {
        text-align: center;
        position: relative;
        top: 45%;
        color: #222;
        transition: all 1s;
        // background: linear-gradient(90deg, rgb(46, 89, 102)  0%, rgb(92, 173, 201) 95%,  #d46e6e 5%);
        
        h2 {
            font-size: 2.5vw;
        }
        h4{
            font-size: 2vw;
            margin: 0;
            position: relative;
            
        }
    }

    .boxes {
        width: 50%;
        float: left;
    }

.box {
    height: 49vh;
    width: 20vw;
    margin: 5px;
    left: -10px;
    position: relative;
    float: left;
    cursor: pointer;
    z-index: 1;
    // opacity: .8;
    // border-radius: 10px;
    background: rgba(255, 255, 255, 0.582);
    transition: background-color 0.2s linear;
    
}
.box:hover {
    opacity: 1;
    background-color: #222;
    
    .day {color:white;}
    

   
}

.fading{
  -webkit-animation-name: fading;
  -webkit-animation-duration: 1.8s;
  animation-name: fading;
  animation-duration: 1.8s;
}

@-webkit-keyframes fading {
  from {opacity: .4} 
  to {opacity: 1}
}

@keyframes fading {
  from {opacity: .4} 
  to {opacity: 1}
}


/////modal

.modal2 {
  position: absolute;
  height: 100vh;
  top: 5px;
  left: 20px;
  z-index: 9;
  background: rgba(34, 34, 34, 0.741);
  
  .modalContainer {
     width: 44vw;
      margin: auto;
    
  }

  .modalHeading {
      padding: 1px;
      background: linear-gradient(45deg, #eb6767 0%, #6ccbeb 100%);
      color: white;
    //   border-radius: 5px;

  }

 

  .modalContent {
      height: 98vh;
    //   padding: 44px;
      margin: 5px;
      opacity: 1;
      background: rgba(0, 0, 0, 0.253);
      background-size: cover;
      background-position-x: 50%; 

       .mcback {
      position: relative;
      height: 98vh;
       width: 100%;
        background-size: cover;
        left: 0;
        top: 0;
        opacity: .5;
        z-index: 1;
      background-position-x: 50%; 
  }

    .mctext {
        position: absolute;
        top:0;
        z-index: 9;
        padding: 55px;
            h2 {
                font-size: 5vw;
                
            }
            h3 {
                font-size: 3vw;
            }
            p {
                font-size: 2vw;
            }
    }
     

      
  }

  .modalContent:after {
      content: '';
      opacity: .5;
  }
  .close {
      
      position: relative;
      padding: 10px 16px 0 0;
      color: white;
      font-size: 38px;
      z-index: 99;
      float: right;
      cursor: pointer;
    
      
  }
  .close:hover {
      transform: scale(1.4);
      transition: all .5s;
  }
}


@media screen and (max-width: 748px) {

    #topics {
        height: 100vh;
    }

   .img-title {
        width: 80vw;
        position: relative;
        padding-top: 250px;
        margin-bottom: -110px; 
    }

    .parallax-mobile {
    background-image: url('../../assets/img/intro/banner.png');
    background-repeat: no-repeat;
    position: absolute;
    z-index: 0;
    left: 0;
    opacity: .4;
    margin-top: 0px;
    background-attachment: fixed;
    background-position: 70% 0px;
    background-size: 300% auto;
    height: 100%;
    width: 100%;
}

.wrapper {
    margin-top: -30px;
    height: 45vh;

}

    .day {
        
        img {
            height: 45px;
            z-index: 1;
            position: relative;
            
        }
        h4{
            font-size: 6vw;
            margin: 0;
            position: relative;
            
        }
    }

.box {
    height: 120px;
    cursor: pointer;
    z-index: 1;
    opacity: .8;
    border-radius: 10px;
    transition: background-color 0.2s linear;
    
}

}


</style>



