<template>
  <div id="welcome" >
     <section class="welcome">

       <div class="container-fluid">

      
       <div class="wel-back row">
 
      


             <div class="col-sm-6 col-xs-12">
          <ul class='circle-container'>
              <button class="tablinks active" id="tab1" v-on:click="selectTab(1)"><i class="fa fa-handshake-o fa-4x" data-fa-transform="shrink-1 down-1"></i></button>
              <button class="tablinks" id="tab2" v-on:click="selectTab(2)"><i class="fa fa-users fa-4x " data-fa-transform="shrink-1 "></i></button>
              <button class="tablinks" id="tab3" v-on:click="selectTab(3)"><octicon name="globe" scale="5"></octicon></button>
              <button class="tablinks" id="tab4" v-on:click="selectTab(4)"><i class="fa fa-book fa-4x " data-fa-transform="shrink-1"></i></button>
              <button class="tablinks" id="tab5" v-on:click="selectTab(5)"><img class="fish-icon" src="../../assets/img/icons/fish-icon.svg" alt=""></button>
          </ul>
       </div>

              <div class="col-sm-6 col-xs-12" v-for="section in sections" >
                  <div :id="section.num" class="tabcontent">
                      <h1>{{section.section}}</h1>
                      <p>{{section.text}}</p>
                  </div>
             </div>

       </div>
       </div>
     </section>
   </div>
</template>

<script>
import Octicon from 'vue-octicon/components/Octicon.vue'
import 'vue-octicon/icons/globe'
import db from  '../../firebase/firebase'


export default {
  name: 'welcome',
  components: {
  Octicon
  },
   data(){
    return {
        sections: []
    }
   },
  methods: {
      buttonClick(){
        var hide = true;
    $('.tablinks').click(function(){

      var self = $(this);

      if (self.hasClass('active')) {
          $('.tablinks').removeClass('active');
          return false;
      }

      $('.tablinks').removeClass('active');

      self.toggleClass('active');
      hide = false;

    
    });

        },  
      selectTab(tabIndex) {
      // Hide All Tabs
      $("#tab1Content").css("opacity", "0");
      $("#tab2Content").css("opacity", "0");
      $("#tab3Content").css("opacity", "0");
      $("#tab4Content").css("opacity", "0");
      $("#tab5Content").css("opacity", "0");
      
      //Show the Selected Tab
        $("#tab"+ tabIndex +'Content').css("opacity", "1");
    }
  },
  mounted(){
 
   this.buttonClick();
  },
  created(){
    db.collection('HomeData').get().then 
    (querySnapshot => {
      querySnapshot.forEach(doc => {
        this.sections.push(doc.data())

      })
    })

  }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
@import '../../assets/main.scss';

@import '../../assets/bootstrap.min';

.welcome {
    background: $gradient-2;
  height: 90vh;
  position: relative;
  z-index: 1;

  .wel-back {
    margin-top: -20px;
  }
}
#tab1Content {
  position: absolute;
 display: block; 
 opacity: 1;
 transition: all .5s ease-in-out;
 
}

#tab2Content, #tab3Content, #tab4Content, #tab5Content  {
  position: absolute;
  opacity: 0;
 

 transition: all .5s ease-in-out;
//  display: none; 


}
.active {
  transform: scale(1.4)!important;
   filter: blur(0px) !important;
  // transform: rotate(189deg)!important;
}
.tablinks {
   filter: blur(3px);

   svg {
     color:white;
   }
   i {
     color:white;
   }
   .fish-icon {
     width: 70px;
     transform: rotate(90deg);
   }
}
.tabcontent {
  // padding: 20px;
  margin-left: -5vw;
  padding-top: 90px;
  height: 80vh;
  color:white;
  width: 100%;

  h1 {
    font-size: 10vmin;
    padding: 0;
    margin: 0;
  }
  p{
    text-indent: 30px;
    color:white;
    width: 90%;
    padding: 0 0 0 0px;
    
    font-size: 1.6vw;
    
  }

  img{
    height: 70px;
    padding-left: 40px;
  }
}


@mixin on-circle($item-count, $circle-size, $item-size) {  
  position: relative;
  width:  $circle-size;
  height: $circle-size;
  border-radius: 50%;
  padding: 0; 
  list-style: none;
  
  > * {
    display: block;
    position: absolute;
    top:  50%; 
    left: 50%;
    margin: -($item-size / 2);
    width:  $item-size;
    height: $item-size;
  
    $angle: (360 / $item-count);
    $rot: 0;

    @for $i from 1 through $item-count {
      &:nth-of-type(#{$i}) {
        transform: rotate($rot * 1deg) translate($circle-size / 1.7) rotate($rot * -1deg);
      }

      $rot: $rot + $angle;
    }
  }
}

.circle-container {
  @include on-circle($item-count: 5, $circle-size: 18em, $item-size: 8em); 
  margin: 150px auto 0;
  border: dotted 5px white;

  button { 
    display: block; 
    border: white solid 6px;
    background: linear-gradient(45deg, #e47474 0%, rgb(120, 221, 255) 100%) no-repeat ;
    background-size: 120% 100%;
    max-width: 100%; 
    border-radius: 50%;
    transition: .5s;
    cursor: pointer;
     
    &:hover {
      filter: brightness(110%);
    }
  }
}







@media screen and (max-width: 748px) {

  .welcome {
  height: 100vh;

}

  .active {
  transform: scale(1.1)!important;
   filter: blur(0px) !important;
  }
.tablinks {
   filter: blur(3px);

   svg {
     color:white;
   }
   i {
     color:white;
     font-size: 9vw;
   }
   .fish-icon {
     width: 40px;
     transform: rotate(90deg);
   }

}

.octicon {
  transform: scale(.6);
}



  .tabcontent {
  padding: 20px;
  padding-top: 100px;
  height: 10vh;
  color:white;

  p{
    color:white;
    width: 100%;
    padding: 0 0 0 0px;
    font-size: 2.5vw;
    
  }

  img{
    height: 55px;
    padding-left: 40px;
  }
}



.circle-container {
  @include on-circle($item-count: 5, $circle-size: 12em, $item-size: 6em); 
  margin: 120px auto 0;
  border: dotted 5px white;

  button { 
    display: block; 
    border: white solid 6px;
    background: linear-gradient(45deg, #e47474 0%, rgb(120, 221, 255) 100%) no-repeat ;
    background-size: 120% 100%;
    max-width: 100%; 
    border-radius: 50%;
    transition: .5s;
    cursor: pointer;
     
    &:hover {
      filter: brightness(110%);
    }
  }
}


}


</style>



