import Vue from 'vue'
import Router from 'vue-router'
import App from '@/App'
import Home from '@/pages/Home.vue'
import Study from '@/pages/Study.vue'
import series from '@/components/study-components/series.vue'
import hymns from '@/components/study-components/hymns.vue'
import Events from '@/pages/Events.vue'
import Gallery from "@/pages/Gallery.vue"
import Map from "@/pages/Map.vue"
import Contact from "@/pages/Contact.vue"
import Member from "@/pages/Member.vue"
import Donate from "@/pages/Donate.vue"
import Dashboard from "@/pages/Dashboard.vue"
import dashHome from '@/components/dash-components/dash-home.vue'
import dashCal from '@/components/dash-components/dash-cal.vue'
import dashTopic from '@/components/dash-components/dash-topic.vue'



Vue.use(Router)

const router = new Router({
  routes: [
    { path: '/', component: Home},
    { path:"/crecimiento", component: Study},
    { path:"/crecimiento/estudios", component: series},
    { path:"/crecimiento/himnos", component: hymns},
    { path:"/calendario", component: Events},
    { path:"/fotos", component: Gallery},
    { path:"/direcciones", component: Map},
    { path:"/contacto", component: Contact},
    { path:"/donar", component: Donate},
    { path:"/miembros", component: Member},
    { path:"/dashboard", component: Dashboard, meta:{requiresAuth: true},
      children: [
        { path:"home", component: dashHome},
        { path: "calendar", component: dashCal},
        { path: "topics", component: dashTopic}
      ]
      }
    // { path:"/dashboard/home", component: dashHome, meta:{requiresAuth: true}}
  ],
  // mode: "history",
})


// router.beforeEach((to, from, next) => {
//   // Check for requiresAuth guard
//   if (to.meta.requiresAuth) {
//     if(firebase.auth().currentUser){
//       next()
//     } else {
//       next({path:"/miembros"})
//     }
//   }
//   next()
// });

export default router;





