<template>
  <div>
      <!-- <div class="row" v-for="day in days" >
          
    </div>       -->

    <div>
        <button @click="pickFile()">Upload Image </button>
       <input type="file" style="display:none" ref="fileInput" accept="image/*" @change="onFilePicked">
        <div>
            <h4>File Preview:</h4>
            <img :src="imageUrl" alt="" style="width: 400px; height:100%;"> 
        <button @click="uploadImage()">Save</button>
        </div>
    </div>
  </div>

</template>

<script>
import firebase from '../../firebase/firebase'


export default {
  name: 'dash-topic',
  data(){
      return {
          text: null,
          imageUrl: "",
          imageURL: '',
          image: null,
          imageFileName: '',
          days: []
      }
  },
    methods: {
        pickFile(){
            this.$refs.fileInput.click()
        },
        onFilePicked(event) {
            const files = event.target.files
            console.log(files)
            let filename = files[0].name;
            if(filename.lastIndexOf('.') <= 0){
                return alert('add a valid file!');
            }

            const fileReader = new FileReader()
            fileReader.addEventListener("load", () => {
                this.imageUrl = fileReader.result;
            })
            fileReader.readAsDataURL(files[0])
            this.image = files[0].name

            this.imageFileName = this.image.substr(0, this.image.lastIndexOf('.'));
   
           
        },
      uploadImage () {

          firebase.storage().ref('topics/' + this.image).then(fileData => {
              imageURL: fileData.metadata.downloadURLs[0]

          })
        // db.collection('TopicsData').where('img', '==', '').get().then((querySnapshot) => {
        //   querySnapshot.forEach((doc) => {
        //     doc.ref.update({
        //       text : this.text
        //     })
        //     .then(() => {
        //     //   this.$router.push({ name: 'view-employee', params: { employee_id: this.employee_id }})
        //     });
        //   })
        // })
      }
    },
    // created(){
    //     db.collection('HomeData').get().then (querySnapshot => {querySnapshot.forEach(doc => {
    //     const data = {
    //       'id': doc.id,
    //       'section': doc.data().section,
    //       'text': doc.data().text
    //     }
    //     this.sections.push(data)

    //     console.log(this.sections)
    //   })
    // })
    // }
    // }
  
}
</script>

