<template>
  <div >

    <loader v-if="loading"/>

     <div v-show="loading === false">
        <div class="col col-sm-12 col-xs-12"> 
            <v-calendar :attributes='attrs' is-single-paned  is-expanded> </v-calendar>
            
                <div class="events-cont container"> 
                    <div id="events">
                    </div>
                    <div class="row one-edge-shadow">
                        <div class="mySlides fading"  v-for="months in events.months" v-if="months.month !== null" v-show="months.id == currentMonth">
                                <h3>{{months.month}}</h3>
                                <div class="divider"></div>
                            <div class="DateDiv one-edge-shadow col-xs-4" v-for="event in months.event" @click="clickedEvent(event); showingModal = true;">
                                <div class="row">
                                    <h4 class="col-xs-1">{{event.name}}</h4>
                                    <span class="col-xs-1 col-xs-offset-3">{{event.date}}</span>
                                    <!-- <span class="DateRange">{{event.month}}</span> -->
                                </div>
                             
                            </div> 
                        </div>
                    </div>
                    <transition name="slide-fade">
                    <div class="modall" id="addModal" v-if="showingModal" >
                        <div class="modalContainer">
                            <div class="modalHeading">
                                <div class="close" @click="showingModal = false;">
                                    &times;
                                </div>
                                <div class="modalContent">
                                    <h4 v-model="eventClicked.name">{{eventClicked.name}}</h4>
                                </div>
                            </div>
                        </div>
                    </div>
                    </transition>
                </div>
        </div>
     </div>
</div> 
</template>

<script>
import json from '../assets/events/events.json';
import db from  '../firebase/firebase';
import axios from 'axios';
import Loader  from '../components/main/Loader.vue';

export default {
  name: 'Events',
  components: {
      "loader": Loader
  },
  data() {
    return {
         attrs: [
            {
            key: 'Cantos',
            dates: { weekdays: [2] },
            highlight: {
                backgroundColor: '#ff8080',
                
            },
            // Just use a normal style
            contentStyle: {
                color: '#fafafa',
            },
            contentHoverStyle: {
                color: 'blue'
            },
            // Our new popover here
            popover: {
                label: 'Cantos! 7-8PM',
            }
            },
            {
                key: 'Estudio',
                dates: {weekdays: [4]},
                highlight: {
                    backgroundColor: 'blue'
                },
            // Just use a normal style
            contentStyle: {
                color: '#fafafa',
            },
            contentHoverStyle: {
                color: '#222'
            },
            // Our new popover here
            popover: {
                label: 'Estudio! 7-8PM',
            }
            },
            // {
            //     key: 'salida',
            //     dates: [new Date(2018, 0, 12)],
            //     highlight: {
            //         backgroundColor: 'yellow',
            // } 
            // }
      ],
      events: {
          months:""
      },
      currentMonth: "",
      eventClicked: {},
      showingModal: false,
      loading: true
    }
  },
   methods: { 
      getEvents(){        

            var d = new Date();
            var m = d.getMonth();
            var slideIndex = m + 1;

            this.currentMonth = slideIndex - 1;

            showSlides(slideIndex);   

            $(".c-arrow-layout .vc-angle-right").click(function(){
                   showSlides(slideIndex += 1);
                   console.log("clicked")
                })

             $(".c-arrow-layout .vc-angle-left").click(function(){
                   showSlides(slideIndex -= 1);
                })

            function currentSlide(n) {
            showSlides(slideIndex = n);
            }
            function showSlides(n) {
            var i;
            var slides = document.getElementsByClassName("mySlides");
            if (n > slides.length) {slideIndex}      
            if (n < 1) {slideIndex}
            for (i = 0; i < slides.length; i++) {
                $(slides[i]).hide();
                
            }

            $(slides[slideIndex-1]).show();

            }
            
      },
      clickedEvent(event){
          this.eventClicked = event;
          console.log("event clicked")
      }
  },
  mounted(){
      this.getEvents();
  },
  created(){

      axios.get("http://iglesiadecristoenelgin.com/Test/events.php").then(res => {

            if(res.data) {
                    this.events.months = res.data;
                    this.loading = false
                }
                }).catch(err => {
                
                if(err.msg) {
                    this.loading = false
                }

      })


  }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>

@import '../assets/main';
@import '../assets/bootstrap.min';

.divider {
    position: relative;
    height: 4px;
    width: 100%;
    left: 0px;
    opacity: .9;
    z-index: 1;
    background: $gradient-2;
    transition: all .7s;
    opacity: .7;
}


.header {
    text-align: center;
}


.slideshow-container {
    position: relative;
    // width: 100%;
    display: block;

  
}

div.c-day-content {
  border-radius: 0%!important;
}


  .mySlides{
      margin-top: 50px;

        h3 {
            color:white;
            font-weight: 300;
            text-align: center;
            margin: 5px;
        }
    }

.events-cont {
    width: 85%;
    margin-top: 20px;
}

.eventMonth {
    height: 100%;
    position: absolute;
}

    .DateDiv {

        width: 150px;
        margin: 15px;
        margin-left: 25px;
        height: 50px;
        font-size: 16px;
        background: $gradient-2;
        border-radius: 10px;
        color: white;
        transition: all .2s ease-out;

        h4 {
            font-weight: 300;
        }
        cursor: pointer;
        span {
            font-style: italic;
            font-size: 12px;
            float: right;
            padding-top:10px;
            padding-right: 45px;
            
        }
        .DateRange {
            display:none;
        }
    }

    .DateDiv:hover {
        transform: scale(1.2);
    }

    /* Fading animation */
.fading{
  -webkit-animation-name: fading;
  -webkit-animation-duration: .7s;
  animation-name: fading;
  animation-duration: .7s;
  
}

@-webkit-keyframes fading {
  from {opacity: .4} 
  to {opacity: 1}
}

@keyframes fading {
  0% {opacity: .1; transform: scale(.8)} 
  50% {opacity: 0; transform: scale(.6)}
  100% {opacity: 1; transform: scale(1)}
}


.modall {
    position: fixed;
    top: 0;
    left: 0;
    bottom: 0;
    right: 0;
    
    .modalContainer {
       width: 70vw;
       background: transparent;
        margin: auto;
        margin-top: 100px;
    }

    .modalHeading {
        padding: 6px;
        background: $gradient-2;
        color: white;
        border-radius: 5px;
    }

    .modalContent {
        min-height: 435px;
        padding: 44px;
        margin: 3px;
        background: rgba(0, 0, 0, 0.363);
    }

    .close {
        padding: 10px 16px 0 0;
        color: white;
        font-size: 38px;
        
    }
    .close:hover {
        transform: scale(1.4);
        transition: all .5s;
    }
}

@media screen and (max-width: 748px) {
 .DateDiv {
     width: 100%;
     margin-top: 5px;
     margin-left: 0;
 }
    // .row {
    //     width: 100%;
    // }
}
</style>



