<template>
  <div>
        <div><h1 id="curtrack" class="text-gradient">SELECT TRACK</h1></div>
    
        <div id="timebox">
          <span id="curtimetext">00:00</span> / <span id="durtimetext">00:00</span>
          
          <div><input id="seekslider" type="range" min="0" max="100" value="0" step="1"></div>

        </div>
  </div>
</template>

<script>
export default {
  name: 'trackcontrols'
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
@import '../../assets/main.scss';


@import '../../assets/bootstrap.min';

   #curtrack {
        font-size: 4vw;
        text-align: center;

    }

    .text-gradient {
        background-position: 20%;
        background-size: 100%;
    }

    #timebox {
        width: 100%;
        color: white;
        text-align: center;
        font-size: 1.3vw;

      
        input#seekslider{
                width:80vw;
                position: relative;
                
                
            }

        input[type='range'] {
                -webkit-appearance: none !important;
                margin:0px;
                padding:0px;
                background: $gradient-2;
                height:13px;
                border-radius: 50px;
            }
            input[type='range']::-ms-fill-lower  {
                background:#000;
            }
            input[type='range']::-ms-fill-upper  {
                background:#000;
            }
            input[type='range']::-moz-range-track {
                border:none;
                background: #000;
            }
            input[type='range']::-webkit-slider-thumb {
                -webkit-appearance: none !important;
                background: white;
                height:23px;
                width:23px;
                border-radius:50%;
                cursor:pointer;
            }
            input[type='range']::-moz-range-thumb {
                background: radial-gradient(#FFF, #333);
                height:11px;
                width:11px;
                border-radius:50px;
                cursor:pointer;
            }
            input[type='range']::-ms-thumb {
                -webkit-appearance: none !important;
                background: radial-gradient(#FFF, #333);
                height:11px;
                width:11px;
                cursor:pointer;                
                border-radius:50px;

            }

    }


@media screen and (max-width: 748px) {

 #curtrack {
        font-size: 6vw;
        text-align: center;
        margin-top: 60px;

    }

 #timebox {
        color: white;
        text-align: center;
        font-size: 3.3vw;
 }
}

</style>



