<template>
  <div id="mission">
      <div>
          <!-- <img src="../../assets/img/intro/cuba.png" alt=""> -->
          <button class="boxshadow center" @click="showingModal = true;">INFORMACION</button>
      </div>

       <transition name="slide-fade">
               <div class="modall" id="addModal" v-if="showingModal" >
                <div class="modalContainer">
                    <div class="modalHeading">
                        <div class="close" @click="showingModal = false;">
                            &times;
                        </div>
                        <div class="modalContent">
                            <div class="row">
                                <div class="text col-sm-6">
                                    <h1>{{missions[0].title}}</h1>
                                    <p>{{missions[0].text}}</p>
                                 </div>
                            <div class="money col-sm-6">
                                <span>$</span>
                             <i-count-up
                                :startVal="0"
                                :endVal= missions[0].count
                                :decimals="0"
                                :duration="2" 
                                :options="options" 
                                  @ready="onReady"
                                ></i-count-up>
                            </div>
                            </div>
                          
                            
                        </div>
                    </div>
                </div>
            </div>
            </transition>
  </div>
</template>

<script>

import ICountUp from 'vue-countup-v2'

// import db from  '../../firebase/firebaseInit'


export default {
  name: 'mission',
  data(){
      return {
            showingModal: false,
            options: {
            useEasing: true,
            useGrouping: true,
            separator: ',',
            decimal: '.',
            prefix: '',
            suffix: '',
           
        },
         missions: []

      }
  },
  components: {
      ICountUp
  },
//   created(){

//     db.collection('MissionData').get().then 
//     (querySnapshot => {
//       querySnapshot.forEach(doc => {
//         const data = {
//           'id': doc.id,
//           'count': doc.data().count,
//           'title': doc.data().title,
//           'text': doc.data().text
//         }
//         this.missions.push(data)
//       })
//     })
//   },
  methods: {
         onReady: function(instance, CountUp) {
        const that = this;
        instance.update(that.endVal + 100);
      }
  }

  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
@import '../../assets/main.scss';


@import '../../assets/bootstrap.min';
#mission {
    height: 100vh;
    position: relative;
    background-image: url('../../assets/img/intro/cuba.png');
    background-size: 100%;
    background-position: -10% 100%;
}

img {
    width: 100%;
    position: relative;

}
button {
    position: absolute;
    top:75vh;
    left: 47%;
    color:white;
    background: $gradient-2;
    padding: 20px;
    font-size: 1.5em;
    border-radius: 5px;
}
.money {
    font-size: 6vw;
    padding: 30px auto;
}
.modall {
    padding-top: 0vh;
}
.modalContent {
    height: 85vh;
}

@media screen and (max-width: 748px) {
#mission {
    height: 100vh;
    position: relative;
    background-image: url('../../assets/img/intro/cuba-mobile.png');
    background-size: 100%;
    background-position: -10% 100%;
}
button {
    position: absolute;
    top:80vh;
}


}


</style>



