<template>
  <div>
      <div class="row" v-for="data in sections">

        <div v-if="editSec === data.section">
         <h1>{{data.section}}</h1>
          <textarea v-model="editText" cols="80" rows="7"></textarea>
         <button type="submit" class="btn" @click="onUpdate()"> Confirm</button>
         <button type="submit" class="btn" @click="onCancel()"> Cancel</button>

      </div>

        <div class="input-field col s12" v-else>
            <h1>{{data.section}}</h1>
            <p>{{data.text}}</p>
            <button class="btn" @click="onEdit(data);">edit</button>

        </div>


    </div>      
  </div>

</template>

<script>
import db from  '../../firebase/firebase'


export default {
  name: 'dash-home',
  data(){
      return {
          sections: [],
          editSec: "",
          editText: "",
          editTab: ""
      }
  },
    methods: {
       getData(){
          db.collection('HomeData').get().then (querySnapshot => {querySnapshot.forEach(doc => {
        
        this.sections.push(doc.data())

      })
    })

    },
    onEdit(section){

        console.log(section)

        this.editSec = section.section
        this.editText = section.text
        this.editTab = section.num


    },
    onCancel(){
        this.$router.go('/dashboard/home');

    },
    onUpdate() {
        db.collection('HomeData').where('section', '==', this.editSec).get().then((querySnapshot) => {
          querySnapshot.forEach((doc) => {
            doc.ref.set({
              section : this.editSec,   
              text : this.editText,
              num : this.editTab

            }).then(this.getData());
          })
          this.onCancel();
        })
      }
    },
  
    mounted(){
        this.getData();
    }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
// @import '../assets/materialize.min.css';


h1 {
    color:white;
}

p {
    color:  lightcyan;
}

</style>



