<template>
  <div id="dashboard">
      
          <div class="sidenav2">
                    <ul>     
                            <li >
                                <router-link to="/dashboard/home" >
                                 <h4>Welcome</h4> 
                                </router-link>
                            </li>  
                            <li >
                                <router-link to="/dashboard/topics" >
                                    <h4>days section</h4> 
                                </router-link>
                            </li>
                            <li >
                                <router-link to="/dashboard/calendar" >
                                    <h4>Calendar</h4> 
                                </router-link>
                            </li>
                          

                        </ul>
                    
            </div>
          <div class="topbar">
                <h1>DASHBOARD</h1>

                 <button class="btn waves-effect waves-light logout white " type="submit" name="action" style="background:#222!important">logout</button>
                <button class="logout" @click="logout()">Logout</button>
          </div>
            
            

      <div class="mainview">
                <transition name="fade"> 
                  <router-view />
                </transition>
      </div>
          
      
  </div>
</template>

<script>
import firebase from 'firebase';

export default {
  name: 'Dashboard',
  data(){
      return {
          isLoggedIn: false,
          currentUser: false
      }
  },
  methods:{
      logout(){
          firebase.auth().signOut().then(() => {
              this.$router.push('/miembros');
          })
      }
  }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>

@import '../assets/main';
@import '../assets/materialize.min.css';

// @import '../assets/bootstrapall.min';

#dashboard {
    position: relative;
    // left: 20px;
    width: 100%;
    top: 0px;
    margin: 0;
    padding: 0;
}

.topbar {
    position: fixed;
    right: 0;
    top:0;
    width: 95%;
    height: 70px;
    background: $gradient-2;
    z-index: 1;
    padding-left: 90px;
    
    h1{
        width: 20%;
        font-size: 20px;
        padding: 0;
        margin: 0;
    }

    .logout {
        position: absolute;
        top: 30%;
        right: 5%;
    }
}

.sidenav2 {
    float: left;
    height: 100vh;
    width: 19%;
    z-index: 0;
    top: 0;
    position: fixed;
    background: rgb(50, 57, 77);

    .material-icons {
        text-align: right;
        float: right;
        color:white;
    }

    ul {
    position: relative;
    top: 55px;
    padding-top: 0px;
    padding-left: 0px;
    width: 100%;
    height: 100%;
    background: rgba(255, 255, 255, 0.37);

    li {
        background: #222;
        width: 100%;
        height: 50px;
        position: relative;


        h4 {
            color:white;
            font-size: 12px;
            text-align: right;
            padding-top: 15px;
             -webkit-margin-before: 0em;
             transition: all .5s;
        }

    }
       li:hover {
           border-left: solid 19px white;

           h4 {
               padding-right: 20px;
           }

        }
}
}

.mainview {
    position: relative;
    width: 70%;
    left: 25%;
    top: 100px;
}





</style>



