<template>
  <div>
      <div class="limiter member">
		<div class="container-login100">
			<div class="wrap-login100">
				<form class="login100-form validate-form" >
					<span class="login100-form-title">	
						 <i class="fa fa-user"></i>
					</span>

					<div class="wrap-input100 validate-input" data-validate = "Valid email is: a@b.c">
						<input class="input100" type="text" name="email"  v-model="email">
						<span class="focus-input100" data-placeholder="Email"></span>
					</div>

					<div class="wrap-input100 validate-input" data-validate="Enter password">
						<span class="btn-show-pass">
							<i class="fa fa-eye eye"></i>
                            <i class="fa fa-eye-slash eye-slash hide"></i>
						</span>
						<input class="input100" type="password" name="password" v-model="password">
						<span class="focus-input100" data-placeholder="Password"></span>
					</div>

					<div class="container-login100-form-btn" >
						<div class="wrap-login100-form-btn">
							<div class="login100-form-bgbtn"></div>
							<button class="login100-form-btn" type="submit" name="login" value="Login" @click="signIn">
								Login
							</button>
						</div>
					</div>
				</form>
                <i class="fa fa-spinner fa-spin"></i>
			</div>
		</div>
	</div>
  </div>
</template>

<script>

import firebase from 'firebase';

export default {
  name: 'Member',
    data () {
            return {
                
                    email:'',
                    password:''
                
            }
        },
    methods:{
      inputValue(){
             $('.input100').each(function(){
        $(this).on('blur', function(){
            if($(this).val().trim() != "") {
                $(this).addClass('has-val');
            }
            else {
                $(this).removeClass('has-val');
            }
        })    
    })
      },
      signIn(e){
        firebase
        .auth()
        .signInWithEmailAndPassword(this.email, this.password)
        .then(
          user => {
            // alert(`You are logged in as ${user.email}`);
            this.$router.push('/dashboard');
          },
          err => {
            alert(err.message);
          }
        );
      e.preventDefault();
            }

  },
  mounted(){
      this.inputValue();
  }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>


@import '../assets/main';
@import '../assets/bootstrap.min';

    .fa-user {
        color: white;
        margin: 0px 0 30px 0;
        // border: 2px solid #f2f2f2;
          background: $gradient-slant;
          background-size: 90% 10%;  
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent; 
        border-radius: 100%;
        padding: 20px;
        opacity: .8;
        font-size: 100px!important;
        // background: $gradient-2;
    }
    .hide {
        display: none;
    }

@media screen and (max-width: 748px) {
  .wrap-login100 {
     width: 90%;
     height: 65vh;
     padding: 30px 25px 13px 25px;
  }


  .input100 {
    font-size: 12px;
  }

  .divider {
      left: -15px;
  }
}


</style>



