<template>
     <div class="containers">
   
    <ul class="accordion" >
      <li class="tab" v-for="plan in plans" >
        <div class="social">
             <h1 class="text-gradient">{{plan.number}}</h1>
          <h2>{{plan.step}}</h2>
        </div>
        <div class="content">
          <h1>{{plan.step}}</h1><br>
          <p v-html="plan.text"></p>
        </div>
      </li>
    </ul>
     <header>
       <h1 >PLAN <br> DE <br> SALVACION</h1>
    </header>
  </div>
</template>

<script>
export default {
  name: 'plan',
  data(){
      return {
          plans: [
            { number: "1", step: "OIR", text: "<strong>DEBES OÍR LA VERDADERA PALABRA DE DIOS</strong><br><br> \"Así que la fe viene por el oír y el oir por la palabra de Dios\". (Romanos 10:17)"},
            { number: "2", step: "CREER", text: "<strong>DEBES CREER QUE JESUS ​​ES EL HIJO VERDADERO DE DIOS</strong><br><br> \"Por eso te dije que morirías en tus pecados, porque si no crees que yo soy Él, morirás en tus pecados\". (Juan 8:24)"},
            { number: "3", step: "ARREPENTIRSE", text: "<strong>DEBES ARREPENTIRTE DE TUS PECADOS</strong><br><br> \"Así que, arrepentíos y convertíos, para que sean borrados vuestros pecados, para que vengan los tiempos de refrigerio de la presencia del Señor\" (Hechos 3:19)."},
            { number: "4", step: "CONFESAR", text: "<strong>DEBES CONFESAR TU FE EN JESUCRISTO</strong><br><br> \"Debes confesar que Jesús es el Señor. Él es el Señor, lo confiesas o no, pero es para tu salvación que debes reconocer su deidad y su propiedad\" (Romanos 10: 9 -10)."},
            { number: "5", step: "BAUTIZARSE", text: "<strong>DEBES SER BAUTIZADO POR LA INMERSIÓN</strong><br><br>\"Sed bautizados para la remisión de los pecados,\" Entonces Pedro les dijo: Arrepentíos, y bautícese cada uno de vosotros en el nombre de Jesucristo para perdón de los pecados, y recibiréis el don del Espíritu Santo '\"(Hechos 2:38)"},
            { number: "6", step: "FIDELIDAD", text: "<strong>DEBES VIVIR UNA VIDA FIEL HASTA LA MUERTE</strong><br><br> \"Vivid una vida cristiana fiel en la comunión del pueblo de Dios\" Por tanto, mis amados hermanos, estad firmes, inamovibles, siempre abundando en la obra del Señor, sabiendo que vuestro trabajo no es en vano en el Señor \"(1 Corintios 15:58) \"Pero si caminamos en la luz como Él está en la luz, tenemos comunión unos con otros, y la sangre de Jesucristo, su Hijo, nos limpia de todo pecado \"( 1 Juan 1: 7)"}
]
              
          
      }
  }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
@import '../../assets/main.scss';


@import '../../assets/bootstrap.min';
* {
  margin: 0;
  padding: 0;
  border: 0;
}

body {
  background-color: #222;
  font-family: Arial, Helvetica, sans-serif;
}

@font-face {
  font-family: 'Genericons';
  src: url("https://s3-us-west-2.amazonaws.com/s.cdpn.io/53819/genericons-regular-webfont.eot");
  src: url("https://s3-us-west-2.amazonaws.com/s.cdpn.io/53819/genericons-regular-webfont.woff") format("woff"), url("https://s3-us-west-2.amazonaws.com/s.cdpn.io/53819/genericons-regular-webfont.eot") format("truetype");
}

.containers {
    position: relative;
//   margin: 50px auto;
  width: 90%;
  height: 80vh;
}

header h1 {
  position:absolute;
  color: #fff;
  opacity: .5;
  font-size: 7vw;
  text-align: right;
  z-index: 0;
  right:-100px;
  top: 0%;
}

.accordion {
  background: transparent;
  position:absolute;
  width:82%;
  min-width: 800px;
  display: block;
  left: 10%;
  list-style-type: none;
  overflow: hidden;
  height: 100%;
  font-size: 0;
  z-index:1;
}

.tab {
  display: inline-block;
  background-color: #444;
  border-right: #333 1px solid;
  width: 80px;
  height: 100%;
  left:0%;
  overflow: hidden;
  position: relative;
  margin: 0;
  transition: all 0.5s ease-in-out 0.1s;
}

.tab:hover .social h2 {
/*   margin-right: 400px;  */
/*     background-color: #ff0000; */

}

.tab:hover {
  left:0%;
  width: 450px;
  background-image: $gradient-2;
}



.tab .content {
  background: #fff;
  width: 360px;
  height: 100%;
  margin-left: 80px;
  padding: 20px 0 0 15px;
  position: relative;
  
}

.tab .content h1 {
  font-size: 2rem;
  margin-bottom: 10px;
  transition: all 0.5s ease-in-out 0.1s;
}

.tab .content p {
  font-size: 1vw;
  padding-right: 30px;
  font-weight: 400;
}
.tab:hover h1 {
    margin-top: 40%;
}

.social h2 {
    cursor: pointer;
  transition: all 0.4s ease-in-out 0.1s;
  width: 80px;
  height: 100%;
  position: absolute;
  margin-right:30%;
  text-align: right;
  display: block;
  color: #fff;
  font-size: 2vw;
  writing-mode: vertical-rl;
  text-orientation: upright;
}
.social h1 {
      transition: all 0.4s ease-in-out 0.1s;
  width: 80px;
  height: 100%;
  position: absolute;
  text-indent: 0;
  margin-right:40%;
  text-align: center;
  display: block;
  color: #fff;
  font-size: 3vw;
}


@media (max-width: 950px) {
  .container {
    width: 70%;
  }

  .tab {
    display: block;
    width: 100%;
     left:0%;
    border-bottom: 3px #333 solid;
  }

  .accordion {
    display: block;
    min-width: 450px;
    height: auto;
  }

  .tab .content {
    width: 85%;
  }

  .tab:hover {
    width: 100%;
  }
  .social h2 {
    margin-right:570px;
  }
}

@media (max-width: 680px) {
  .container {
    width: 95%;
  }

  .accordion {
    width: 100%;
    min-width: 350px;
  }
  .social h2 {
    margin-right:305px;
  }
}

</style>



